// ============================================================
// TOEFL Writing Vocabulary Engine
// Note: The only use of innerHTML is for pre-built clause tags
// generated by our own ct() function - these are safe static
// HTML strings, not user input. All user-facing content uses
// textContent or DOM createElement.
// ============================================================

// --- Clause tag helper (generates safe static HTML) ---
function ct(cls,label){var s=document.createElement("span");s.className="ct "+cls;s.textContent=label;return s.outerHTML;}
var M=ct("ct-m","Main"),OBJ=ct("ct-obj","Object Cl."),ATTR=ct("ct-attr","Relative Cl."),
CAU=ct("ct-cau","Causal Adv."),CON=ct("ct-con","Concessive Adv."),COND=ct("ct-cond","Conditional"),
TIM=ct("ct-time","Temporal Adv."),PURP=ct("ct-purp","Purpose Adv."),SUBJ=ct("ct-subj","Subject Cl."),
APPO=ct("ct-appo","Appositive Cl."),PART=ct("ct-part","Participial Ph.");

// --- Global state ---
var DATA={task1:[],task2:[],task3:[]};
var MODULES={task1:{patterns:[],distractors:[]},task2:{verbs:[],clusters:[]},task3:{profTemplates:[]}};
var currentTab="task1";
var currentSub={task2:"all"};
var activeFilters={task1:{pos:new Set(),stars:new Set()},task2:{pos:new Set(),stars:new Set()},task3:{pos:new Set(),stars:new Set()}};
var mastered=JSON.parse(localStorage.getItem("toefl_m2")||"{}");

// --- Category metadata per task ---
var CAT_META={
  task1:{dialog:{l:"Dialogue",c:"dialog"},grammar:{l:"Grammar Pattern",c:"grammar"},trap:{l:"Distractor/Trap",c:"trap"},output:{l:"Writing Output",c:"output"}},
  task2:{prompt:{l:"Scenario",c:"prompt"},instr:{l:"Instruction",c:"instr"},email:{l:"Email Writing",c:"email"},cross:{l:"Cross-theme",c:"cross"}},
  task3:{prof:{l:"Professor Q",c:"prof"},stu:{l:"Student Opinion",c:"stu"},write:{l:"Test-taker",c:"write"},arg:{l:"Argumentation",c:"arg"},sum:{l:"Conclusion",c:"sum"}}
};

// --- Tab switching (handled by HTML inline script for unified nav) ---
// The switchPane function is defined in the HTML and handles both
// bottom nav and top tabs. This section kept for backwards compatibility.
var tabBarEl=document.getElementById("tabBar");
if(tabBarEl){
  tabBarEl.addEventListener("click",function(e){
    var btn=e.target.closest(".tab-btn");if(!btn)return;
    var t=btn.getAttribute("data-t");
    if(typeof switchPane==="function"){switchPane(t);}
    else{
      currentTab=t;
      document.querySelectorAll(".tab-btn").forEach(function(b){b.classList.remove("active");});
      btn.classList.add("active");
      document.querySelectorAll(".tab-pane").forEach(function(p){p.classList.remove("active");});
      var pane=document.getElementById("pane-"+t);
      if(pane)pane.classList.add("active");
      if(t==="quiz")initQuiz();
    }
  });
}

// --- Theme (handled by HTML inline script for unified toggle) ---
// Theme setup moved to HTML to coordinate header button + settings toggle.
// Engine no longer manages theme directly.

// --- Register data (called from data files) ---
function registerTask(task, words, modules){
  DATA[task]=words||[];
  if(modules)MODULES[task]=modules;
  buildFilters(task);
  buildModules(task);
  renderWords(task);
  updateHeaderStats();
}

// --- Build filter chips ---
function buildFilters(task){
  var words=DATA[task];
  var posSet=new Set();
  words.forEach(function(w){posSet.add(w.pos);});
  var filterEl=document.getElementById("filter-"+task);
  if(!filterEl)return;
  while(filterEl.children.length>1)filterEl.removeChild(filterEl.lastChild);
  posSet.forEach(function(p){
    var c=document.createElement("button");c.className="chip";c.textContent=p;
    c.setAttribute("data-pos",p);
    c.addEventListener("click",function(){
      this.classList.toggle("on");
      if(this.classList.contains("on"))activeFilters[task].pos.add(p);
      else activeFilters[task].pos.delete(p);
      renderWords(task);
    });
    filterEl.appendChild(c);
  });
  var starsEl=document.getElementById("stars-"+task);
  if(!starsEl)return;
  while(starsEl.children.length>1)starsEl.removeChild(starsEl.lastChild);
  [1,2,3].forEach(function(n){
    var c=document.createElement("button");c.className="chip";
    c.textContent="\u2b50".repeat(n);
    c.addEventListener("click",function(){
      this.classList.toggle("on");
      if(this.classList.contains("on"))activeFilters[task].stars.add(n);
      else activeFilters[task].stars.delete(n);
      renderWords(task);
    });
    starsEl.appendChild(c);
  });
  if(task==="task2"){
    var subBar=document.getElementById("sub-task2");
    if(subBar && subBar.children.length===0){
      var cats=["all","suggest","complain","request","thank","invite","resolve"];
      var catLabels={all:"All",suggest:"Suggest/Recommend",complain:"Complain/Feedback",request:"Request Help",thank:"Thank/Praise",invite:"Invite/Plan",resolve:"Resolve/Explain"};
      cats.forEach(function(cat){
        var b=document.createElement("button");
        b.className="sub-btn"+(cat==="all"?" on":"");
        b.textContent=catLabels[cat]||cat;
        b.addEventListener("click",function(){
          subBar.querySelectorAll(".sub-btn").forEach(function(x){x.classList.remove("on");});
          this.classList.add("on");
          currentSub.task2=cat;
          renderWords("task2");
        });
        subBar.appendChild(b);
      });
    }
  }
  var searchEl=document.getElementById("search-"+task);
  if(searchEl && !searchEl._bound){
    searchEl._bound=true;
    searchEl.addEventListener("input",function(){renderWords(task);});
  }
}

// --- Build special modules ---
function buildModules(task){
  var container=document.getElementById(task.replace("task","t")+"-modules");
  if(!container)return;
  container.textContent="";
  var mods=MODULES[task];
  if(!mods)return;

  if(task==="task1" && mods.patterns && mods.patterns.length){
    var mc=createModule(typeof ICON!=="undefined"?ICON.clipboard(16):"\ud83d\udcdd","Grammar Structure Patterns","Wh- + Aux + S + V and other key sentence patterns for Build a Sentence");
    var body=mc.querySelector(".module-body");
    mods.patterns.forEach(function(p){
      var d=document.createElement("div");d.className="pattern";
      var f=document.createElement("div");f.className="pattern-formula";f.textContent=p.formula;
      d.appendChild(f);
      p.examples.forEach(function(ex){
        var e=document.createElement("div");e.className="pattern-ex";
        setEmHTML(e,ex.en);
        d.appendChild(e);
        var c=document.createElement("div");c.className="pattern-cn";c.textContent=ex.cn;
        d.appendChild(c);
      });
      body.appendChild(d);
    });
    container.appendChild(mc);
  }
  if(task==="task1" && mods.distractors && mods.distractors.length){
    var mc2=createModule(typeof ICON!=="undefined"?ICON.alertTriangle(16):"\u26a0\ufe0f","Distractor Word Identification","OG confirms some questions include an extra word not used in the answer. Learn to spot the trap.");
    var body2=mc2.querySelector(".module-body");
    mods.distractors.forEach(function(d){
      var row=document.createElement("div");row.className="distractor";
      var q=document.createElement("div");q.className="distractor-q";
      setEmHTML(q,d.sentence);
      var ans=document.createElement("button");ans.className="distractor-ans";ans.textContent="Show extra word";
      ans.addEventListener("click",function(){
        if(this.classList.contains("show")){this.textContent="Show extra word";this.classList.remove("show");}
        else{this.textContent=d.extra;this.classList.add("show");}
      });
      row.appendChild(q);row.appendChild(ans);
      body2.appendChild(row);
    });
    container.appendChild(mc2);
  }
  if(task==="task2" && mods.verbs && mods.verbs.length){
    var mc3=createModule(typeof ICON!=="undefined"?ICON.search(16):"\ud83d\udd0d","Instruction Verb Comparison","describe vs explain vs suggest vs request vs mention vs recommend - know the difference to stay on topic");
    var body3=mc3.querySelector(".module-body");
    var grid=document.createElement("div");grid.className="verb-compare";
    mods.verbs.forEach(function(v){
      var box=document.createElement("div");box.className="verb-box";
      var h=document.createElement("h4");h.textContent=v.word;box.appendChild(h);
      var def=document.createElement("div");def.className="vb-def";def.textContent=v.cn;box.appendChild(def);
      v.examples.forEach(function(ex){
        var e=document.createElement("div");e.className="vb-ex";e.textContent=ex;box.appendChild(e);
      });
      if(v.diff){var df=document.createElement("div");df.className="vb-diff";df.textContent=v.diff;box.appendChild(df);}
      grid.appendChild(box);
    });
    body3.appendChild(grid);
    container.appendChild(mc3);
  }
  if(task==="task2" && mods.clusters && mods.clusters.length){
    var mc4=createModule(typeof ICON!=="undefined"?ICON.puzzle(16):"\ud83e\udde9","Scenario Word Clusters","Words that co-occur in email prompts - memorize as groups for 3x efficiency");
    var body4=mc4.querySelector(".module-body");
    mods.clusters.forEach(function(cl){
      var d=document.createElement("div");d.className="cluster";
      var n=document.createElement("div");n.className="cluster-name";n.textContent=cl.name;d.appendChild(n);
      var ww=document.createElement("div");ww.className="cluster-words";
      cl.words.forEach(function(w){
        var sp=document.createElement("span");sp.className="cluster-word";sp.textContent=w;ww.appendChild(sp);
      });
      d.appendChild(ww);
      var se=document.createElement("div");se.className="cluster-sentence";
      setEmHTML(se,cl.sentence);
      d.appendChild(se);
      body4.appendChild(d);
    });
    container.appendChild(mc4);
  }
  if(task==="task3" && mods.profTemplates && mods.profTemplates.length){
    var mc5=createModule(typeof ICON!=="undefined"?ICON.crosshair(16):"\ud83c\udfaf","Professor Question Templates","Recognizing these patterns tells you exactly what direction to write");
    var body5=mc5.querySelector(".module-body");
    mods.profTemplates.forEach(function(t){
      var d=document.createElement("div");d.className="prof-tpl";
      var f=document.createElement("div");f.className="prof-tpl-pattern";f.textContent=t.pattern;d.appendChild(f);
      t.examples.forEach(function(ex){
        var e=document.createElement("div");e.className="prof-tpl-ex";e.textContent=ex;d.appendChild(e);
      });
      var tip=document.createElement("div");tip.className="prof-tpl-tip";tip.textContent="\u2192 "+t.tip;d.appendChild(tip);
      body5.appendChild(d);
    });
    container.appendChild(mc5);
  }
}

function createModule(icon,title,desc){
  var mc=document.createElement("div");mc.className="module-card";
  var head=document.createElement("div");head.className="module-head";
  var ic=document.createElement("span");ic.className="module-icon";
  if(icon.indexOf("<svg")===0){ic.innerHTML=icon;}else{ic.textContent=icon;}
  var ti=document.createElement("span");ti.className="module-title";ti.textContent=title;
  var ar=document.createElement("span");ar.className="module-arrow";if(typeof ICON!=="undefined"){ar.innerHTML=ICON.chevronDown(14);}else{ar.textContent="\u25bc";}
  head.appendChild(ic);head.appendChild(ti);head.appendChild(ar);
  head.addEventListener("click",function(){mc.classList.toggle("open");});
  mc.appendChild(head);
  var body=document.createElement("div");body.className="module-body";
  if(desc){var p=document.createElement("p");p.style.cssText="font-size:.78rem;color:var(--muted);margin-bottom:10px";p.textContent=desc;body.appendChild(p);}
  mc.appendChild(body);
  return mc;
}

// --- Render word cards ---
function renderWords(task){
  var words=DATA[task]||[];
  var q=(document.getElementById("search-"+task)||{}).value||"";
  q=q.toLowerCase();
  var filtered=words.filter(function(w){
    if(q && w.w.toLowerCase().indexOf(q)===-1 && w.cn.indexOf(q)===-1) return false;
    if(activeFilters[task].pos.size && !activeFilters[task].pos.has(w.pos)) return false;
    if(activeFilters[task].stars.size && !activeFilters[task].stars.has(w.stars||1)) return false;
    if(task==="task2" && currentSub.task2 && currentSub.task2!=="all"){
      if(w.cat!==currentSub.task2 && w.cat!=="all") return false;
    }
    return true;
  });
  var totalSents=0;
  filtered.forEach(function(w){totalSents+=w.ss.length;});
  var masteredCount=words.filter(function(w){return mastered[task+"_"+w.w];}).length;
  var statsEl=document.getElementById("stats-"+task);
  if(statsEl){
    statsEl.textContent="";
    appendText(statsEl,"Showing ");appendBold(statsEl,filtered.length);
    appendText(statsEl," / "+words.length+" words | ");
    appendBold(statsEl,totalSents);appendText(statsEl," sentences | Mastered: ");
    appendBold(statsEl,masteredCount);appendText(statsEl," / "+words.length);
  }
  var progEl=document.getElementById("prog-"+task);
  if(progEl) progEl.style.width=(words.length?Math.round(masteredCount/words.length*100):0)+"%";
  var grid=document.getElementById("grid-"+task);
  if(!grid)return;
  grid.textContent="";
  var meta=CAT_META[task]||{};
  filtered.forEach(function(w){
    var card=document.createElement("div");card.className="word-card";
    var head=document.createElement("div");head.className="wc-head";
    var sp1=document.createElement("span");sp1.className="wc-word";sp1.textContent=w.w;
    var sp2=document.createElement("span");sp2.className="wc-ph";sp2.textContent=w.ph;
    var sp3=document.createElement("span");sp3.className="wc-pos";sp3.textContent=w.pos;
    var sp4=document.createElement("span");sp4.className="wc-cn";sp4.textContent=w.cn;
    var sp5=document.createElement("span");sp5.className="wc-stars";
    if(typeof ICON!=="undefined"){var _s="";for(var _i=0;_i<(w.stars||1);_i++)_s+=ICON.star(12);sp5.innerHTML=_s;}
    else{sp5.textContent="\u2b50".repeat(w.stars||1);}
    var spacer=document.createElement("span");spacer.className="wc-spacer";
    var lbl=document.createElement("label");lbl.style.cssText="display:flex;align-items:center;gap:4px;font-size:.7rem;color:var(--dim);cursor:pointer";
    var cb=document.createElement("input");cb.type="checkbox";cb.checked=!!mastered[task+"_"+w.w];
    cb.style.accentColor="var(--accent)";
    cb.addEventListener("change",(function(t,word){return function(){
      if(this.checked)mastered[t+"_"+word]=true;else delete mastered[t+"_"+word];
      localStorage.setItem("toefl_m2",JSON.stringify(mastered));
      renderWords(t);updateHeaderStats();
    };})(task,w.w));
    lbl.appendChild(cb);lbl.appendChild(document.createTextNode("Mastered"));
    var arrow=document.createElement("span");arrow.className="wc-arrow";if(typeof ICON!=="undefined"){arrow.innerHTML=ICON.chevronDown(14);}else{arrow.textContent="\u25bc";}
    // TTS sound button
    var soundBtn=document.createElement("button");soundBtn.className="wc-sound";
    if(typeof ICON!=="undefined"){soundBtn.innerHTML=ICON.volume(14);}else{soundBtn.textContent="\ud83d\udd0a";}
    // Sound button: direct gesture tap -> always speaks (even if TTS toggle is off)
    var soundHandler=(function(word){return function(e){
      e.stopPropagation();e.preventDefault();
      if(typeof speakWord==="function")speakWord(word,true);
    };})(w.w);
    soundBtn.addEventListener("click",soundHandler);
    soundBtn.addEventListener("touchend",soundHandler);
    head.appendChild(sp1);head.appendChild(sp2);head.appendChild(sp3);head.appendChild(sp5);
    head.appendChild(soundBtn);head.appendChild(sp4);head.appendChild(spacer);head.appendChild(lbl);head.appendChild(arrow);
    head.addEventListener("click",function(e){
      if(e.target.tagName==="INPUT"||e.target.closest(".wc-sound"))return;
      card.classList.toggle("open");
      // Auto-speak when opening (non-direct gesture, respects TTS toggle)
      if(card.classList.contains("open")&&typeof speakWord==="function")speakWord(w.w,false);
    });
    card.appendChild(head);
    var body=document.createElement("div");body.className="wc-body";
    w.ss.forEach(function(s,si){
      var catKey=s[0];var ci=meta[catKey]||{l:catKey,c:catKey};
      var sent=document.createElement("div");sent.className="sent";
      var shead=document.createElement("div");shead.className="s-head";
      var snum=document.createElement("span");snum.className="s-num s-num-"+ci.c;snum.textContent=(si+1);
      var scat=document.createElement("span");scat.className="s-cat";scat.textContent=ci.l;
      var sen=document.createElement("span");sen.className="s-en";setEmHTML(sen,s[1]);
      var sar=document.createElement("span");sar.className="s-arrow";if(typeof ICON!=="undefined"){sar.innerHTML=ICON.chevronDown(12);}else{sar.textContent="\u25bc";}
      shead.appendChild(snum);shead.appendChild(scat);shead.appendChild(sen);shead.appendChild(sar);
      shead.addEventListener("click",function(){sent.classList.toggle("open");});
      sent.appendChild(shead);
      var detail=document.createElement("div");detail.className="s-detail";
      var a1=document.createElement("div");a1.className="ana";
      var l1=document.createElement("span");l1.className="ana-label l-pos";l1.textContent="POS";
      var v1=document.createElement("span");v1.className="ana-val";v1.textContent=s[2];
      a1.appendChild(l1);a1.appendChild(document.createTextNode(" "));a1.appendChild(v1);detail.appendChild(a1);
      var a2=document.createElement("div");a2.className="ana";
      var l2=document.createElement("span");l2.className="ana-label l-str";l2.textContent="STRUCT";
      var v2=document.createElement("span");v2.className="ana-val";
      // Structure field contains only our own ct() output - safe pre-built HTML
      v2.innerHTML=s[3];
      a2.appendChild(l2);a2.appendChild(document.createTextNode(" "));a2.appendChild(v2);detail.appendChild(a2);
      var a3=document.createElement("div");a3.className="ana";
      var l3=document.createElement("span");l3.className="ana-label l-cn";l3.textContent="CN";
      var v3=document.createElement("span");v3.className="ana-val";v3.textContent=s[4];
      a3.appendChild(l3);a3.appendChild(document.createTextNode(" "));a3.appendChild(v3);detail.appendChild(a3);
      sent.appendChild(detail);body.appendChild(sent);
    });
    card.appendChild(body);grid.appendChild(card);
  });
}

function updateHeaderStats(){
  var el=document.getElementById("hdrStats");if(!el)return;
  var total=DATA.task1.length+DATA.task2.length+DATA.task3.length;
  var sents=0;
  ["task1","task2","task3"].forEach(function(t){DATA[t].forEach(function(w){sents+=w.ss.length;});});
  var mc=Object.keys(mastered).length;
  el.textContent="";
  appendText(el,"Total: ");appendBold(el,total);appendText(el," words | ");
  appendBold(el,sents);appendText(el," sentences | Mastered: ");appendBold(el,mc);
}

// --- Quiz ---
var quizState={pool:[],current:null,score:0,total:0,taskFilter:"all"};
function initQuiz(){
  var ctrl=document.getElementById("quizControls");ctrl.textContent="";
  ["all","task1","task2","task3"].forEach(function(t){
    var b=document.createElement("button");b.className="chip"+(t===quizState.taskFilter?" on":"");
    b.textContent=t==="all"?"All Tasks":t.replace("task","Task ");
    b.addEventListener("click",function(){
      ctrl.querySelectorAll(".chip").forEach(function(x){x.classList.remove("on");});
      this.classList.add("on");quizState.taskFilter=t;startQuiz();
    });
    ctrl.appendChild(b);
  });
  startQuiz();
}
function startQuiz(){
  quizState.score=0;quizState.total=0;quizState.pool=[];
  var tasks=quizState.taskFilter==="all"?["task1","task2","task3"]:[quizState.taskFilter];
  tasks.forEach(function(t){DATA[t].forEach(function(w){
    quizState.pool.push({task:t,w:w.w,cn:w.cn,ex:w.ss.length?w.ss[0][1]:""});
  });});
  shuffle(quizState.pool);updateQuizScore();nextQuizQuestion();
}
function nextQuizQuestion(){
  var area=document.getElementById("quizArea");area.textContent="";
  if(quizState.pool.length===0){
    var done=document.createElement("div");done.className="quiz-card";
    done.textContent="All done! Score: "+quizState.score+" / "+quizState.total;
    area.appendChild(done);
    var restart=document.createElement("button");restart.className="quiz-next";restart.textContent="Restart";
    restart.addEventListener("click",startQuiz);area.appendChild(restart);return;
  }
  var q=quizState.pool.shift();quizState.current=q;
  var options=[q.w];
  var allW=[];
  ["task1","task2","task3"].forEach(function(t){DATA[t].forEach(function(w){if(w.w!==q.w)allW.push(w.w);});});
  shuffle(allW);
  for(var i=0;i<3&&i<allW.length;i++)options.push(allW[i]);
  shuffle(options);
  var card=document.createElement("div");card.className="quiz-card";
  var showCn=Math.random()>0.4;
  var prompt=document.createElement("div");prompt.className="quiz-prompt";
  prompt.textContent=showCn?q.cn:"Which word fits?";card.appendChild(prompt);
  if(!showCn){
    var ctx=document.createElement("div");ctx.className="quiz-context";
    ctx.textContent=q.ex.replace(/<\/?em>/g,"___");card.appendChild(ctx);
  }
  var optGrid=document.createElement("div");optGrid.className="quiz-options";
  options.forEach(function(opt){
    var btn=document.createElement("button");btn.className="quiz-opt";btn.textContent=opt;
    btn.addEventListener("click",function(){
      quizState.total++;
      optGrid.querySelectorAll(".quiz-opt").forEach(function(b){b.classList.add("disabled");if(b.textContent===q.w)b.classList.add("correct");});
      if(opt===q.w)quizState.score++;else this.classList.add("wrong");
      updateQuizScore();setTimeout(nextQuizQuestion,1200);
    });
    optGrid.appendChild(btn);
  });
  card.appendChild(optGrid);area.appendChild(card);
}
function updateQuizScore(){
  var el=document.getElementById("quizScore");el.textContent="";
  appendText(el,"Score: ");appendBold(el,quizState.score);
  appendText(el," / "+quizState.total+" | Remaining: "+quizState.pool.length);
}

// --- Helpers ---
function shuffle(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));var t=a[i];a[i]=a[j];a[j]=t;}}
function appendText(el,t){el.appendChild(document.createTextNode(t));}
function appendBold(el,t){var b=document.createElement("b");b.textContent=t;el.appendChild(b);}
function setEmHTML(el,html){
  var parts=html.split(/<\/?em>/);
  for(var i=0;i<parts.length;i++){
    if(i%2===0)el.appendChild(document.createTextNode(parts[i]));
    else{var em=document.createElement("em");em.textContent=parts[i];el.appendChild(em);}
  }
}
